using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Cosmos indexes are no longer configured by EF in .NET 9.
        // HasIndex() now throws. Remove it — manage indexes via Azure portal/IaC instead.

        // Breaking change 2: Discriminator property renamed from "Discriminator" to "$type".
        // To keep reading existing documents that use "Discriminator":
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 3: Id format changed from "EntityType|Key" to just "Key".
        // To keep reading existing documents with "Blog|1" format:
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<LegacyCosmosIdValueGenerator>();
    }
}

// Breaking change 4: Raw SQL queries using c.Discriminator must be updated
// if you did NOT apply fix #2 above. Since we kept "Discriminator" via
// HasDiscriminator, existing queries like
//   SELECT * FROM c WHERE c.Discriminator = 'Blog'
// will continue to work unchanged.

class Blog { public string Id { get; set; } public string Name { get; set; } }

// Value generator that preserves the legacy "Discriminator|Key" id format
// so existing documents remain accessible.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var entityType = entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue;
        return $"{entityType}|{key}";
    }
}

